import{_ as t,o as n,c as a,ae as i}from"./chunks/framework.BivGZUvz.js";const p=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started.md","filePath":"getting-started.md"}'),o={name:"getting-started.md"};function s(r,e,d,c,l,h){return n(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>Welcome to the HoneyHive Semantic Conventions documentation.</p><h2 id="what-are-semantic-conventions" tabindex="-1">What are Semantic Conventions? <a class="header-anchor" href="#what-are-semantic-conventions" aria-label="Permalink to &quot;What are Semantic Conventions?&quot;">​</a></h2><p>Semantic conventions define a standard set of attribute names, types, and meanings for observability telemetry in AI applications. By adhering to these conventions, all HoneyHive SDKs and integrations maintain consistency in how they describe AI interactions, LLM calls, datasets, evaluations, and platform events.</p><h2 id="using-semantic-conventions-in-your-sdk" tabindex="-1">Using Semantic Conventions in Your SDK <a class="header-anchor" href="#using-semantic-conventions-in-your-sdk" aria-label="Permalink to &quot;Using Semantic Conventions in Your SDK&quot;">​</a></h2><p>When instrumenting your application with HoneyHive SDKs, the conventions are already baked in—SDK methods automatically populate attributes according to these standards. You rarely need to reference the conventions directly, but understanding them helps you interpret observability data in the HoneyHive platform and write more effective queries and evaluations.</p><p>For detailed attribute definitions and examples, browse the full Registry section. Each attribute includes its type, expected values, and usage context.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>This page is a placeholder for the scaffolded documentation site. Future PRs will add full reference documentation, integration guides, and best practices for working with semantic conventions across different platforms and SDKs.</p>',9)])])}const m=t(o,[["render",s]]);export{p as __pageData,m as default};
